local G = DYCLegendary local require = G.DYCModRequire local fns = {} local Round = function(num) return math.floor(num + 0.5) end local Clamp = function(num, min, max) return math.min(math.max(num, min), max) end local Lerp = function(n1, n2, p) return(n2 - n1) * p + n1 end local function IsAliveOrNoHealth(inst) local isValid = inst and inst.IsValid and inst:IsValid() local health = inst and inst.components.health if isValid and not health then return true end if isValid and health and health.IsDead then return not health:IsDead() end return false end fns.IsAliveOrNoHealth = IsAliveOrNoHealth local function IsAlive(inst) if not inst or not inst:IsValid() then return false end local health = inst.components.health if health and health.currenthealth > 0x0 then return true end return false end fns.IsAlive = IsAlive local function IsDead(inst) if not inst or not inst:IsValid() then return false end local health = inst.components.health if health and health.currenthealth <= 0x0 then return true end return false end fns.IsDead = IsDead local function IsAAllyToB(inst, inst2) local follower = inst.components.follower local follower2 = inst2.components.follower local rider = inst2.components.rider local driver = inst2.components.driver local isEntValid = inst:IsValid() and not inst:HasTag( "FX" ) and not inst:HasTag( "NOCLICK" ) and not inst:HasTag( "INLIMBO" ) and not inst:HasTag( "DECOR" ) local isAlly = isEntValid and ((inst:HasTag( "chester" ) and inst2:HasTag( "player" )) or (inst2:HasTag( "chester" ) and inst:HasTag( "player" )) or inst == inst2 or (follower and follower.leader == inst2) or (follower2 and follower2.leader == inst) or (follower and follower2 and follower.leader == follower2.leader and follower.leader ~= nil) or (rider and rider.mount == inst) or (driver and driver.vehicle == inst)) return isAlly end fns.IsAAllyToB = IsAAllyToB local function CanHit(inst, doer) local isAlly = IsAAllyToB(inst, doer) local canHit = inst ~= doer and not isAlly return canHit end fns.CanHit = CanHit local function Freeze(target, coldness) coldness = coldness or 0x1 local freezable = target.components.freezable if freezable then freezable:AddColdness(coldness) freezable:SpawnShatterFX() end local burnable = target.components.burnable if burnable then if burnable:IsBurning() then burnable:Extinguish() elseif burnable.IsSmoldering and burnable.SmotherSmolder and burnable:IsSmoldering() then burnable:SmotherSmolder() end end end fns.Freeze = Freeze local function Ignite(target, doer, colorStr) local burnable = target.components.burnable local health = target.components.health local canBurn = health and burnable and not target.components.fueled or target:HasTag( "player" ) if canBurn then target:AddBuff(colorStr == "blue" and "burn_blue" or "burn" , doer) end end fns.Ignite = Ignite local function CanPoison(target) local poisonable = target.components.poisonable local health = target.components.health if poisonable and target:HasTag( "poisonable" ) and poisonable:CanBePoisoned() and health and health.vulnerabletopoisondamage then return true elseif not poisonable and health and target.prefab and target.prefab ~= "wx78" then return true end return false end fns.CanPoison = CanPoison local function Poison(target, doer) if CanPoison(target) then target:AddBuff( "poison" , doer) end end fns.Poison = Poison local function CurePoison(target) local poisonable = target.components.poisonable if poisonable and poisonable.Cure and poisonable.IsPoisoned and poisonable:IsPoisoned() then poisonable:Cure() end target:RemoveBuff( "poison" ) end fns.CurePoison = CurePoison local function ReduceSanity(target, value) local sanity2 = target.components.sanity if sanity2 then sanity2:DoDelta( - value) end end fns.ReduceSanity = ReduceSanity local function HolyDamage(target, value, attacker) local health = target.components.health if health then health:DoDelta( - value, false, attacker and type(attacker) == "table" and attacker.prefab or attacker and type(attacker) == "string" and attacker or "NIL" ) end end fns.HolyDamage = HolyDamage local function Attack(target, damage, attacker, weapon) local combat = target.components.combat local health = target.components.health if combat and (not health or health.currenthealth > 0x0) then combat:GetAttacked(attacker, damage, weapon) end end fns.Attack = Attack local function Heal(inst, value) value = value or 0x1 local health = inst.components.health if health then health:DoDelta(value, true) end end fns.Heal = Heal local function CreateDummy() local inst = CreateEntity() inst.entity:AddTransform() inst:AddTag( "FX" ) inst:AddTag( "NOCLICK" ) inst.persists = false return inst end fns.CreateDummy = CreateDummy local function AddLightChild(inst, r, g, b) inst.lightChild = CreateEntity() inst:AddChild(inst.lightChild) inst.lightChild.entity:AddTransform() inst.lightChild.entity:AddLight() local light = inst.lightChild.Light light:SetColour(r or 0x1, g or 0x1, b or 0x1) light:SetFalloff(0.5) light:SetIntensity(0.8) light:SetRadius(1.5) inst.lightChild.lightRadius = 1.5 light:Enable(true) local oldRemove = inst.lightChild.Remove inst.lightChild.Remove = function(lightChild) if inst:IsValid() then inst:RemoveChild(lightChild) lightChild.Transform:SetPosition(inst:GetPosition():Get()) end lightChild:DoPeriodicTask(FRAMES, function() lightChild.lightRadius = lightChild.lightRadius - FRAMES * 0x2 if lightChild.lightRadius > 0x0 then lightChild.Light:SetRadius(lightChild.lightRadius) else oldRemove(lightChild) end end) end return inst.lightChild end fns.AddLightChild = AddLightChild return fns 